#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define TABLE_SIZE 10

typedef struct Entry {
    char* key;
    int value;
    struct Entry* next;
} Entry;

typedef struct {
    Entry** buckets;
    int size;
    int count;
} HashTable;

unsigned int hash(const char* key, int size) {
    unsigned int hash = 0;
    while (*key) {
        hash = hash * 31 + *key++;
    }
    return hash % size;
}

HashTable* createTable(int size) {
    HashTable* table = malloc(sizeof(HashTable));
    table->size = size;
    table->count = 0;
    table->buckets = calloc(size, sizeof(Entry*));
    return table;
}

void insert(HashTable* table, const char* key, int value) {
    unsigned int index = hash(key, table->size);

    Entry* entry = malloc(sizeof(Entry));
    entry->key = strdup(key);
    entry->value = value;
    entry->next = table->buckets[index];
    table->buckets[index] = entry;
    table->count++;

    printf("Inserted: %s -> %d at index %d\n", key, value, index);
}

int search(HashTable* table, const char* key) {
    unsigned int index = hash(key, table->size);
    Entry* entry = table->buckets[index];

    while (entry) {
        if (strcmp(entry->key, key) == 0) {
            return entry->value;
        }
        entry = entry->next;
    }
    return -1;  // Not found
}

int main() {
    HashTable* table = createTable(TABLE_SIZE);
    insert(table, "apple", 100);
    insert(table, "banana", 200);
    insert(table, "cherry", 300);

    printf("Search 'apple': %d\n", search(table, "apple"));
    printf("Search 'grape': %d\n", search(table, "grape"));
    return 0;
}

