import java.util.*;

class HashTable<K, V> {
    private class Entry {
        K key;
        V value;
        Entry(K k, V v) { key = k; value = v; }
    }

    private LinkedList<Entry>[] buckets;
    private int size;
    private int count;

    @SuppressWarnings("unchecked")
    public HashTable(int size) {
        this.size = size;
        this.count = 0;
        buckets = new LinkedList[size];
        for (int i = 0; i < size; i++) {
            buckets[i] = new LinkedList<>();
        }
    }

    private int hash(K key) {
        return Math.abs(key.hashCode()) % size;
    }

    public void insert(K key, V value) {
        int index = hash(key);

        // Update if exists
        for (Entry e : buckets[index]) {
            if (e.key.equals(key)) {
                e.value = value;
                return;
            }
        }

        buckets[index].add(new Entry(key, value));
        count++;
    }

    public V search(K key) {
        int index = hash(key);
        for (Entry e : buckets[index]) {
            if (e.key.equals(key)) {
                return e.value;
            }
        }
        return null;
    }

    public boolean delete(K key) {
        int index = hash(key);
        Iterator<Entry> it = buckets[index].iterator();
        while (it.hasNext()) {
            if (it.next().key.equals(key)) {
                it.remove();
                count--;
                return true;
            }
        }
        return false;
    }

    public double loadFactor() {
        return (double) count / size;
    }

    public static void main(String[] args) {
        HashTable<String, Integer> ht = new HashTable<>(10);
        ht.insert("apple", 100);
        ht.insert("banana", 200);
        ht.insert("cherry", 300);

        System.out.println("Search 'apple': " + ht.search("apple"));
        System.out.println("Search 'grape': " + ht.search("grape"));
        System.out.println("Load factor: " + ht.loadFactor());
    }
}
